from flask import Flask, session, url_for, redirect

app = Flask(__name__)
app.secret_key = 'your_secret_key_here'

# Define allowed redirect destinations (server-side route names or IDs)
ALLOWED_REDIRECTS = ['dashboard', 'profile', 'settings']

def login_redirect(next_url=None):
    if next_url is not None:
        # Validate the destination before redirecting
        if next_url in ALLOWED_REDIRECTS:
            return redirect(url_for(next_url))
        else:
            # Handle invalid or untrusted destinations (e.g., log an error)
            print(f"Invalid redirect destination: {next_url}")
    else:
        # Redirect to a default destination (e.g., the dashboard) if no next URL is provided
        return redirect(url_for('dashboard'))

# Example usage:
@app.route('/login', methods=['POST'])
def login():
    # Authenticate user...
    session['user'] = 'authenticated_user'
    
    # Redirect to intended destination after authentication
    return login_redirect(next_url='dashboard')

